content.content:
   1→/* ── Mobile top header ── Hidden on desktop ── */
   2→.mobile-top-header{
   3→    display: none;
   4→}
   5→.mobile-write-btn{
   6→    display: none;
   7→}
   8→
   9→.newsfeed-header{
  10→}
  11→.search-shell{
  12→    position: sticky;
  13→    top: 0;
  14→    z-index: 14;
  15→    align-self: stretch;
  16→    width: 100%;
  17→    max-width: 100%;
  18→}
  19→.search-top-bar{
  20→    position: relative;
  21→    z-index: 12;
  22→    display: flex;
  23→    align-items: center;
  24→    gap: 0.5rem;
  25→    width: 100%;
  26→    padding: 0.65rem 0.75rem 0.75rem 0.75rem;
  27→    box-sizing: border-box;
  28→    background: var(--bg-primary);
  29→    border-bottom: 1px solid var(--border-card);
  30→}
  31→.search-input-wrap{
  32→    position: relative;
  33→    display: flex;
  34→    align-items: center;
  35→    flex: 1;
  36→}
  37→.search-icon{
  38→    position: absolute;
  39→    left: 0.85rem;
  40→    width: 15px;
  41→    height: 15px;
  42→    color: var(--text-faint);
  43→    pointer-events: none;
  44→    transition: color 0.25s ease, transform 0.25s ease;
  45→}
  46→.search-input-wrap:focus-within .search-icon{
  47→    color: #D4A853;
  48→    transform: scale(1.08);
  49→}
  50→.search-input{
  51→    width: 100%;
  52→    border: 1.5px solid var(--border-card);
  53→    border-radius: 10px;
  54→    padding: 0.6rem 0.9rem 0.6rem 2.4rem;
  55→    font-family: var(--font-ui);
  56→    font-size: 0.84rem;
  57→    font-weight: 450;
  58→    letter-spacing: 0.01rem;
  59→    color: var(--text-heading);
  60→    background: var(--bg-secondary);
  61→    outline: none;
  62→    transition: border-color 0.3s ease, box-shadow 0.3s ease, background 0.3s ease;
  63→}
  64→.search-input::placeholder{
  65→    color: var(--text-faint);
  66→    font-weight: 400;
  67→    letter-spacing: 0.015rem;
  68→}
  69→.search-input:focus{
  70→    border-color: #D4A853;
  71→    background: var(--bg-card);
  72→    box-shadow:
  73→        0 0 0 3px rgba(212, 168, 83, 0.1),
  74→        0 2px 8px rgba(212, 168, 83, 0.06);
  75→}
  76→.search-clear-btn{
  77→    border: 1.5px solid var(--border-card);
  78→    background: var(--bg-secondary);
  79→    color: var(--text-secondary);
  80→    border-radius: 8px;
  81→    font-family: var(--font-ui);
  82→    font-size: 0.7rem;
  83→    font-weight: 600;
  84→    letter-spacing: 0.02rem;
  85→    padding: 0.4rem 0.72rem;
  86→    cursor: pointer;
  87→    transition: background 0.2s ease, border-color 0.2s ease, color 0.2s ease;
  88→    white-space: nowrap;
  89→}
  90→.search-clear-btn:hover{
  91→    background: var(--bg-hover);
  92→    border-color: #D4A853;
  93→    color: #D4A853;
  94→}
  95→/* ── Nav row (Stories) ── */
  96→.search-nav-row{
  97→    display: flex;
  98→    gap: 6px;
  99→    padding: 0.4rem 0.75rem;
 100→}
 101→.search-nav-btn{
 102→    display: flex;
 103→    align-items: center;
 104→    justify-content: center;
 105→    gap: 0.35rem;
 106→    flex: 1;
 107→    border-radius: 999px;
 108→    font-family: var(--font-ui);
 109→    font-size: 0.74rem;
 110→    font-weight: 700;
 111→    letter-spacing: 0.01rem;
 112→    padding: 0.48rem 0.7rem;
 113→    cursor: pointer;
 114→    white-space: nowrap;
 115→    transition: background 0.15s ease, transform 0.15s ease, box-shadow 0.15s ease;
 116→}
 117→.search-nav-btn:active{
 118→    transform: scale(0.97);
 119→}
 120→.search-nav-stories{
 121→    border: 1.5px solid rgba(234, 179, 56, 0.35);
 122→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.12), rgba(255, 204, 51, 0.08));
 123→    color: #e6a817;
 124→}
 125→.search-nav-stories:hover{
 126→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.22), rgba(255, 204, 51, 0.16));
 127→    box-shadow: 0 0 10px rgba(234, 179, 56, 0.15);
 128→}
 129→.search-nav-following{
 130→    border: 1.5px solid rgba(234, 179, 56, 0.35);
 131→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.12), rgba(255, 204, 51, 0.08));
 132→    color: #e6a817;
 133→}
 134→.search-nav-following:hover{
 135→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.22), rgba(255, 204, 51, 0.16));
 136→    box-shadow: 0 0 10px rgba(234, 179, 56, 0.15);
 137→}
 138→.search-nav-active{
 139→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.30), rgba(255, 204, 51, 0.22));
 140→    box-shadow: 0 0 12px rgba(234, 179, 56, 0.2);
 141→    border-color: rgba(234, 179, 56, 0.55);
 142→}
 143→.search-mode-pill{
 144→    display: flex;
 145→    align-items: center;
 146→    border-radius: 8px;
 147→    border: 1.5px solid var(--border-card);
 148→    background: var(--bg-secondary);
 149→    color: var(--text-faint);
 150→    font-family: var(--font-ui);
 151→    font-size: 0.65rem;
 152→    font-weight: 650;
 153→    letter-spacing: 0.04rem;
 154→    text-transform: uppercase;
 155→    padding: 0.35rem 0.6rem;
 156→    white-space: nowrap;
 157→}
 158→.search-gallery-hint{
 159→    margin: 0 0.75rem 0.45rem 0.75rem;
 160→    width: fit-content;
 161→    border: 1.5px solid var(--border-card);
 162→    background: var(--bg-secondary);
 163→    color: var(--accent-sage);
 164→    border-radius: 8px;
 165→    font-family: var(--font-ui);
 166→    font-size: 0.68rem;
 167→    font-weight: 600;
 168→    letter-spacing: 0.01rem;
 169→    padding: 0.34rem 0.62rem;
 170→    cursor: pointer;
 171→    transition: background 0.2s ease, border-color 0.2s ease;
 172→}
 173→.search-gallery-hint:hover{
 174→    background: var(--bg-hover);
 175→    border-color: var(--accent-sage);
 176→}
 177→.search-empty-state{
 178→    display: flex;
 179→    justify-content: center;
 180→    align-items: center;
 181→    width: 100%;
 182→    padding: 2rem 0.5rem;
 183→    font-family: var(--font-ui);
 184→    font-size: 0.84rem;
 185→    font-weight: 500;
 186→    color: var(--text-faint);
 187→    letter-spacing: 0.01rem;
 188→}
 189→.search-empty-state.is-canvas-only{
 190→    flex-wrap: wrap;
 191→    gap: 0.28rem;
 192→}
 193→.search-empty-link{
 194→    border: none;
 195→    background: transparent;
 196→    color: var(--accent-sage);
 197→    font-family: var(--font-ui);
 198→    font-size: 0.84rem;
 199→    font-weight: 650;
 200→    cursor: pointer;
 201→    text-decoration: underline;
 202→}
 203→.search-empty-link:hover{
 204→    opacity: 0.88;
 205→}
 206→.search-suggestions-dropdown{
 207→    position: absolute;
 208→    left: 0.75rem;
 209→    right: 0.75rem;
 210→    top: calc(100% - 0.15rem);
 211→    z-index: 30;
 212→    border: 1.5px solid var(--border-card);
 213→    border-radius: 10px;
 214→    background: var(--bg-elevated);
 215→    box-shadow:
 216→        0 8px 24px rgba(0, 0, 0, 0.1),
 217→        0 2px 8px rgba(0, 0, 0, 0.06);
 218→    max-height: 320px;
 219→    overflow-y: auto;
 220→    padding: 0.3rem 0;
 221→    animation: searchDropdownIn 0.2s ease-out;
 222→}
 223→@keyframes searchDropdownIn{
 224→    from{
 225→        opacity: 0;
 226→        transform: translateY(-6px);
 227→    }
 228→    to{
 229→        opacity: 1;
 230→        transform: translateY(0);
 231→    }
 232→}
 233→.search-suggestion-item{
 234→    width: 100%;
 235→    text-align: left;
 236→    border: none;
 237→    background: transparent;
 238→    cursor: pointer;
 239→    display: flex;
 240→    flex-direction: column;
 241→    gap: 0.15rem;
 242→    padding: 0.6rem 0.85rem;
 243→    transition: background 0.15s ease;
 244→    border-left: 2.5px solid transparent;
 245→}
 246→.search-suggestion-item:hover{
 247→    background: var(--bg-pill);
 248→    border-left-color: #D4A853;
 249→}
 250→.search-suggestion-title{
 251→    font-family: var(--font-ui);
 252→    font-size: 0.8rem;
 253→    font-weight: 600;
 254→    color: var(--text-heading);
 255→    white-space: nowrap;
 256→    overflow: hidden;
 257→    text-overflow: ellipsis;
 258→}
 259→.search-suggestion-meta{
 260→    font-family: var(--font-ui);
 261→    font-size: 0.68rem;
 262→    font-weight: 450;
 263→    color: var(--text-faint);
 264→    letter-spacing: 0.01rem;
 265→}
 266→.search-suggestion-muted{
 267→    color: var(--text-faint);
 268→    cursor: default;
 269→    border-left-color: transparent !important;
 270→}
 271→.postcards-parent-container{
 272→    position: relative;
 273→    display: flex;
 274→    flex-direction: column;
 275→    align-items: center;
 276→    width: 100%;
 277→    margin-bottom: 1rem;
 278→    gap: 16px;
 279→    padding: 0 16px;
 280→    box-sizing: border-box;
 281→}
 282→.postcards-parent-loading-container{
 283→    position: relative;
 284→    top: 90px;
 285→    display: flex;
 286→    justify-content: center;
 287→    align-items: center;
 288→    flex-direction: column;
 289→    width: 100%;
 290→    height: 100vh;
 291→}
 292→.loading-newsfeed-bg{
 293→    display: flex;
 294→    justify-content: center;
 295→    align-items: center;
 296→    width: 100%;
 297→    height: 100%;
 298→}
 299→.jounral-view-image{
 300→    width: 400px;
 301→    height: auto;
 302→}
 303→.inview{
 304→    display: flex;
 305→    justify-content: center;
 306→    align-items: center;
 307→    width: 100%;
 308→    min-height: 35px;
 309→}
 310→
 311→/* ── Card ── */
 312→.cards{
 313→    position: relative;
 314→    display: flex;
 315→    flex-direction: column;
 316→    justify-content: flex-start;
 317→    align-items: center;
 318→    width: 99%;
 319→    max-width: 100%;
 320→    min-height: fit-content;
 321→    background-color: var(--bg-card);
 322→    border: 1px solid var(--border-card);
 323→    border-radius: 12px;
 324→    overflow: visible;
 325→    cursor: pointer;
 326→    transition: box-shadow 0.25s ease, transform 0.25s ease;
 327→}
 328→.cards:hover{
 329→    box-shadow: 0 6px 24px rgba(80, 60, 40, 0.07);
 330→    transform: translateY(-2px);
 331→}
 332→
 333→.bookmarked-content-message-container{
 334→    position: absolute;
 335→    top: 100px;
 336→    background-color: rgb(72, 208, 135);
 337→    color: rgb(255, 255, 255);
 338→    font-size: 0.78rem;
 339→    font-weight: 600;
 340→    padding: 0.45rem 1rem;
 341→    border-radius: 8px;
 342→    width: fit-content;
 343→    z-index: 11;
 344→    transition: ease-in-out 0.2s;
 345→}
 346→
 347→/* ── Banner image ── */
 348→.card-image-banner{
 349→    width: 100%;
 350→    max-height: 220px;
 351→    object-fit: cover;
 352→    display: block;
 353→    border-bottom: 1px solid var(--border-card);
 354→    border-radius: 12px 12px 0 0;
 355→    transition: opacity 0.2s ease;
 356→}
 357→.cards:hover .card-image-banner{
 358→    opacity: 0.95;
 359→}
 360→
 361→/* ── Card content area ── */
 362→.card-content{
 363→    display: flex;
 364→    flex-direction: column;
 365→    gap: 0.8rem;
 366→    width: 100%;
 367→    padding: 1rem 1.15rem 0.6rem 1.15rem;
 368→    box-sizing: border-box;
 369→}
 370→
 371→/* ── User info row ── */
 372→.user-info{
 373→    display: flex;
 374→    justify-content: space-between;
 375→    align-items: center;
 376→}
 377→.user-info-child-container{
 378→    display: flex;
 379→    align-items: center;
 380→    height: 100%;
 381→    gap: 0.4rem;
 382→    width: fit-content;
 383→}
 384→.user-avatar-container{
 385→    display: flex;
 386→    align-items: center;
 387→    justify-content: center;
 388→    width: fit-content;
 389→    height: fit-content;
 390→    cursor: pointer;
 391→}
 392→.user-info-avatar{
 393→    width: 22px;
 394→    height: 22px;
 395→    border-radius: 50%;
 396→    object-fit: cover;
 397→}
 398→.user-avatar-container.avatar-ring-legend{
 399→    border-radius: 50%;
 400→    border: 2px solid #FFD700;
 401→    box-shadow:
 402→        0 0 6px 1px rgba(255, 215, 0, 0.5),
 403→        0 0 12px 2px rgba(255, 215, 0, 0.35),
 404→        0 0 20px 4px rgba(255, 215, 0, 0.2);
 405→    animation: glow-legend 2s ease-in-out infinite alternate;
 406→}
 407→.user-avatar-container.avatar-ring-og{
 408→    border-radius: 50%;
 409→    border: 2px solid #9B59FF;
 410→    box-shadow:
 411→        0 0 6px 1px rgba(155, 89, 255, 0.5),
 412→        0 0 12px 2px rgba(155, 89, 255, 0.35),
 413→        0 0 20px 4px rgba(155, 89, 255, 0.2);
 414→    animation: glow-og 2s ease-in-out infinite alternate;
 415→}
 416→
 417→@keyframes glow-legend {
 418→    from {
 419→        box-shadow:
 420→            0 0 6px 1px rgba(255, 215, 0, 0.5),
 421→            0 0 12px 2px rgba(255, 215, 0, 0.35),
 422→            0 0 20px 4px rgba(255, 215, 0, 0.2);
 423→    }
 424→    to {
 425→        box-shadow:
 426→            0 0 8px 2px rgba(255, 215, 0, 0.6),
 427→            0 0 16px 4px rgba(255, 215, 0, 0.4),
 428→            0 0 24px 6px rgba(255, 215, 0, 0.25);
 429→    }
 430→}
 431→
 432→@keyframes glow-og {
 433→    from {
 434→        box-shadow:
 435→            0 0 6px 1px rgba(155, 89, 255, 0.5),
 436→            0 0 12px 2px rgba(155, 89, 255, 0.35),
 437→            0 0 20px 4px rgba(155, 89, 255, 0.2);
 438→    }
 439→    to {
 440→        box-shadow:
 441→            0 0 8px 2px rgba(155, 89, 255, 0.6),
 442→            0 0 16px 4px rgba(155, 89, 255, 0.4),
 443→            0 0 24px 6px rgba(155, 89, 255, 0.25);
 444→    }
 445→}
 446→.user-name-container{
 447→    display: flex;
 448→    align-items: center;
 449→    gap: 0.2rem;
 450→}
 451→.user-newsfeed-name{
 452→    font-family: var(--font-ui);
 453→    font-size: 0.78rem;
 454→    font-weight: 600;
 455→    letter-spacing: 0.005rem;
 456→    margin: 0;
 457→    padding: 0;
 458→    cursor: pointer;
 459→    color: var(--text-secondary);
 460→    transition: color 0.15s ease;
 461→}
 462→.user-newsfeed-name:hover{
 463→    text-decoration: underline;
 464→    color: var(--accent-sage);
 465→}
 466→.name-info-separator{
 467→    display: flex;
 468→    justify-content: center;
 469→    align-items: center;
 470→    width: fit-content;
 471→    height: fit-content;
 472→    color: var(--text-separator);
 473→    font-size: 0.4rem;
 474→    user-select: none;
 475→}
 476→.user-info-email-container{
 477→    display: none;
 478→}
 479→.user-info-email{
 480→    padding: 0;
 481→    margin: 0;
 482→    font-family: var(--font-ui);
 483→    font-size: 0.75rem;
 484→    font-weight: 400;
 485→    color: var(--text-faint);
 486→}
 487→.user-post-date-container{
 488→    display: flex;
 489→    justify-content: center;
 490→    align-items: center;
 491→    width: fit-content;
 492→    height: fit-content;
 493→    cursor: default;
 494→    user-select: none;
 495→}
 496→.user-post-privacy{
 497→    display: flex;
 498→    justify-content: center;
 499→    align-items: center;
 500→    width: fit-content;
 501→    height: fit-content;
 502→    cursor: default;
 503→    user-select: none;
 504→    color: var(--text-heading);
 505→}
 506→.user-post-date{
 507→    padding: 0;
 508→    margin: 0;
 509→    font-family: var(--font-ui);
 510→    font-size: 0.75rem;
 511→    font-weight: 400;
 512→    color: var(--text-faint);
 513→}
 514→.user-post-settings{
 515→    position: relative;
 516→    display: flex;
 517→    flex-direction: column;
 518→    justify-self: flex-end;
 519→    width: fit-content;
 520→    height: fit-content;
 521→    cursor: pointer;
 522→    user-select: none;
 523→    color: var(--text-heading);
 524→}
 525→.setting-modal{
 526→    display: flex;
 527→    justify-content: center;
 528→    align-items: center;
 529→    position: absolute;
 530→    right: 25px;
 531→    bottom: 10px;
 532→    width: 200px;
 533→    height: 100px;
 534→    border-radius: 10px;
 535→    z-index: 200;
 536→    background-color: var(--bg-elevated);
 537→    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.12);
 538→    border: 1px solid var(--border-card);
 539→}
 540→
 541→/* ── Content (title + text) ── */
 542→.content-container{
 543→    display: flex;
 544→    flex-direction: column;
 545→    justify-content: flex-start;
 546→    align-items: flex-start;
 547→    user-select: none;
 548→    gap: 0.5rem;
 549→}
 550→.feed-text-content-container{
 551→    display: flex;
 552→    flex-direction: column;
 553→    width: 100%;
 554→    height: 100%;
 555→    justify-content: flex-start;
 556→    align-items: flex-start;
 557→    gap: 0.35rem;
 558→}
 559→.feed-title-content{
 560→    display: flex;
 561→    justify-content: center;
 562→    align-items: center;
 563→}
 564→.cards.is-canvas-card .feed-title-content{
 565→    flex-direction: row;
 566→    justify-content: flex-start;
 567→    gap: 0.45rem;
 568→}
 569→.feed-title{
 570→    margin: 0;
 571→    padding: 0;
 572→    font-family: "Lexend Deca", sans-serif;
 573→    font-size: 1.1rem;
 574→    font-weight: 700;
 575→    line-height: 1.45;
 576→    letter-spacing: -0.025rem;
 577→    color: var(--text-heading);
 578→}
 579→.feed-text-content{
 580→    padding: 0;
 581→    margin: 0;
 582→    font-family: var(--font-serif);
 583→    font-weight: 400;
 584→    color: var(--text-body);
 585→    line-height: 1.7;
 586→    font-size: 0.88rem;
 587→    letter-spacing: 0.005rem;
 588→}
 589→
 590→.canvas-card-actions{
 591→    display: flex;
 592→    flex-wrap: wrap;
 593→    gap: 0.42rem;
 594→    width: 100%;
 595→    margin-top: -0.1rem;
 596→}
 597→
 598→.canvas-card-action-btn{
 599→    border: 1px solid var(--border-card);
 600→    background: var(--bg-secondary);
 601→    color: var(--text-secondary);
 602→    border-radius: 999px;
 603→    padding: 0.3rem 0.65rem;
 604→    font-size: 0.68rem;
 605→    font-weight: 620;
 606→    cursor: pointer;
 607→    transition: border-color 0.2s ease, background 0.2s ease, color 0.2s ease;
 608→}
 609→
 610→.canvas-card-action-btn:hover{
 611→    border-color: var(--accent-sage);
 612→    color: var(--accent-sage);
 613→}
 614→
 615→.canvas-card-action-btn.is-remix{
 616→    border-color: color-mix(in srgb, var(--accent-purple) 42%, var(--border-card));
 617→    color: var(--accent-purple);
 618→}
 619→
 620→/* ── Icon bar ── */
 621→.card-icons-container{
 622→    display: flex;
 623→    flex-wrap: wrap;
 624→    width: 100%;
 625→    padding: 0.5rem 1.15rem 0.85rem 1.15rem;
 626→    min-height: 22px;
 627→    align-items: center;
 628→    justify-content: flex-start;
 629→    gap: 0.5rem;
 630→    box-sizing: border-box;
 631→    border-top: 1px solid var(--border-card);
 632→}
 633→#card-icons{
 634→    display: flex;
 635→    justify-content: center;
 636→    align-items: center;
 637→    padding: 0.35rem;
 638→    border-radius: 50%;
 639→    transition: background-color 0.2s ease;
 640→    gap: 0.3rem;
 641→}
 642→#card-icons-view{
 643→    display: flex;
 644→    justify-content: center;
 645→    align-items: center;
 646→    padding: 0.1rem;
 647→    border-radius: 50%;
 648→    transition: background-color 0.2s ease;
 649→    gap: 0.3rem;
 650→}
 651→.card-icons{
 652→    display: flex;
 653→    width: fit-content;
 654→    height: fit-content;
 655→    justify-content: center;
 656→    align-items: center;
 657→}
 658→.icon-container{
 659→    display: flex;
 660→    justify-content: center;
 661→    align-items: center;
 662→}
 663→.icon-container p{
 664→    font-family: var(--font-ui);
 665→}
 666→
 667→.like-button:hover .svg-like path{
 668→    fill: rgb(255, 116, 116);
 669→}
 670→.like-button:hover{
 671→    background-color: rgba(255, 161, 161, 0.12);
